INSERT INTO products VALUES (89, 'en', 'ByOZUvD1xJT0FbpeBOTlM', '/rfsw-42', true, 'hXhove6SDtsimjGSGhtkH', 'RFSW-42', true, '<p>The glass design controller with two output relays is used to control&nbsp;appliances and lights.</p><p>The touch buttons on the circuit breaker allow you to directly control&nbsp;the output relay as well as other components of the installation.</p><p>The backlight intensity (white LED) of the buttons is automatically&nbsp;adjusted depending on the ambient lighting.</p><p>They can be combined with detectors, controllers, iNELS Wireless, or&nbsp;system components.</p><p>6 functions – button, impulse relay, and time function of a delayed&nbsp;start or return with a time setting of 2 s - 60 min. Any function can be&nbsp;assigned to each output relay.</p><p>Possibility to set the memory of the output state during a power&nbsp;failure and subsequent restoration of the power supply.</p><p>Each of the outputs can be controlled by up to 12/12 channels (1&nbsp;channel represents one button on the controller).</p><p>Range up to 160 m (in open space), if the signal is insufficient between&nbsp;the controller and unit, use the signal repeater RFRP-20N or protocol&nbsp;component RFIO2 that supports this feature.</p><p>Communication frequency with bidirectional protocol RFIO2.</p>', true, NULL, '[]', 'product', 1768906800000, '[]', 'RFSW-42', 'Glass touch controller with output relays, 4 buttons, sharp', '[{"image":{"uploadId":696,"alt":""},"alt":""}]', '8595188188913', '8891', 20, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfsw-42/share_dokumentace/en/manual_rfsw-xx2_en-cz.pdf', '', '', '', 1768911922547, 1768911922547, '/rfsw-42                                                                                                                                                         rfsw-42                                                                                                                                                          <p>the glass design controller with two output relays is used to control&nbsp;appliances and lights.</p><p>the touch buttons on the circuit breaker allow you to directly control&nbsp;the output relay as well as other components of the installation.</p><p>the backlight intensity (white led) of the buttons is automatically&nbsp;adjusted depending on the ambient lighting.</p><p>they can be combined with detectors, controllers, inels wireless, or&nbsp;system components.</p><p>6 functions – button, impulse relay, and time function of a delayed&nbsp;start or return with a time setting of 2 s - 60 min. any function can be&nbsp;assigned to each output relay.</p><p>possibility to set the memory of the output state during a power&nbsp;failure and subsequent restoration of the power supply.</p><p>each of the outputs can be controlled by up to 12/12 channels (1&nbsp;channel represents one button on the controller).</p><p>range up to 160 m (in open space), if the signal is insufficient between&nbsp;the controller and unit, use the signal repeater rfrp-20n or protocol&nbsp;component rfio2 that supports this feature.</p><p>communication frequency with bidirectional protocol rfio2.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfsw-42/share_dokumentace/en/datasheet_rfsw-xx.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfsw-42/share_dokumentace/en/ec_declaration_of_conformity_rfsw-xx_24v_v2.pdf"},{"url":"https://eshop.elkoep.com/documents/rfx/rfsw-42/share_dokumentace/en/ec_declaration_of_conformity_rfsw-xx_230v_v2.pdf"}]');
INSERT INTO products VALUES (104, 'en', 'HdypayRXhV8EXC6Yotr7z', '/rfja-32b-sl', true, 'LY_4xVf5juCFdeUOgFDmZ', 'RFJA-32B-SL', true, '<p>The switching unit for shutters has 2 output channels used to control&nbsp;garage doors, gates, blinds, awnings…</p><p>They can be combined with Controllers or iNELS RF Control System&nbsp;Components.</p><p>The BOX version offers to mount directly in the installation box, ceiling, or motor drive cover.</p><p>RFJA-32B / 230V: connection of switched load 2x 8 A (2x 2000 W), with&nbsp;the possibility of connecting existing wire buttons.</p><p>Short presses of the controller allow tilting of the slats, and long pressing&nbsp;of the raise / lower moves the blinds to the end position.</p><p>Each component can be controlled by up to 25 channels (1 channel&nbsp;represents one assigned controller).</p><p>The programming button on the device also serves as a manual output&nbsp;control.</p><p>For components, the repeater function can be set via the RFAF / USB&nbsp;service device.</p><p>Range up to 200 m (outdoors), in case of insufficient signal between&nbsp;the controller and the device, use the RFRP-20 signal repeater or components with the RFIO2 protocol that support this function.</p><p>Communication frequency with bidirectional protocol iNELS RF Control2 (RFIO2).</p><p>The contact material of the AgSnO2.</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RFJA-32B-SL', 'Switch unit for the shutters', '[{"image":{"uploadId":759,"alt":""},"alt":""}]', '8595188182546', '8254', 26, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfja-32b-sl/share_dokumentace/en/manual_rfja-32b-sl.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFJA-32B-SL/3D/3d.html', '', 1768999208251, 1768999208251, '/rfja-32b-sl                                                                                                                                                     rfja-32b-sl                                                                                                                                                      <p>the switching unit for shutters has 2 output channels used to control&nbsp;garage doors, gates, blinds, awnings…</p><p>they can be combined with controllers or inels rf control system&nbsp;components.</p><p>the box version offers to mount directly in the installation box, ceiling, or motor drive cover.</p><p>rfja-32b / 230v: connection of switched load 2x 8 a (2x 2000 w), with&nbsp;the possibility of connecting existing wire buttons.</p><p>short presses of the controller allow tilting of the slats, and long pressing&nbsp;of the raise / lower moves the blinds to the end position.</p><p>each component can be controlled by up to 25 channels (1 channel&nbsp;represents one assigned controller).</p><p>the programming button on the device also serves as a manual output&nbsp;control.</p><p>for components, the repeater function can be set via the rfaf / usb&nbsp;service device.</p><p>range up to 200 m (outdoors), in case of insufficient signal between&nbsp;the controller and the device, use the rfrp-20 signal repeater or components with the rfio2 protocol that support this function.</p><p>communication frequency with bidirectional protocol inels rf control2 (rfio2).</p><p>the contact material of the agsno2.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfja-32b-sl/share_dokumentace/en/datasheet_rfja-32b-sl.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfja-32b-sl/share_dokumentace/en/ec_declaration_of_conformity_rfja-32b-sl_230v.pdf"}]');
INSERT INTO products VALUES (110, 'en', 'LK35TfZj1snOa0H4bN7rG', '/rfus-61', true, 'ZD_1ltfTiTfHOisi9_UMk', 'RFUS-61', true, '<p>The switching unit with a 1x 12 A output channel is used for controlling appliances, sockets, or lights.</p><p>They can be combined with detectors, controllers, iNELS RF Control, or system components.</p><p>Multi-function design – button, impulse relay, and time function of delayed ON or OFF with time setting of 2 s – 60 min.</p><p>The switching unit may be controlled by up to 25 channels.</p><p>The programming button on the unit is also used for manual control of the output.</p><p>Range up to 200 m (in open space), if the signal is insufficient between the controller and unit, use the signal repeater RFRP20 or protocol component RFIO2 that supports this feature.</p><p>Communication frequency with bidirectional protocol RFIO2.</p><p>The increased IP 65 protection is suited to mounting on the wall or in harsh environments such as the cellar, garage, or bathrooms.</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RFUS-61', 'Switch unit with increased protection', '[{"image":{"uploadId":764,"alt":""},"alt":""}]', '8595188145268', '5853', 26, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfus-x1/share_dokumentace/en/manual_rfus-61.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFUS-x1/3D/3d.html', '', 1769002305863, 1769002305863, '/rfus-61                                                                                                                                                         rfus-61                                                                                                                                                          <p>the switching unit with a 1x 12 a output channel is used for controlling appliances, sockets, or lights.</p><p>they can be combined with detectors, controllers, inels rf control, or system components.</p><p>multi-function design – button, impulse relay, and time function of delayed on or off with time setting of 2 s – 60 min.</p><p>the switching unit may be controlled by up to 25 channels.</p><p>the programming button on the unit is also used for manual control of the output.</p><p>range up to 200 m (in open space), if the signal is insufficient between the controller and unit, use the signal repeater rfrp20 or protocol component rfio2 that supports this feature.</p><p>communication frequency with bidirectional protocol rfio2.</p><p>the increased ip 65 protection is suited to mounting on the wall or in harsh environments such as the cellar, garage, or bathrooms.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfus-x1/share_dokumentace/en/datasheet_rfus-61.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfus-x1/share_dokumentace/en/ec_declaration_of_conformity_rfus-61,%20rfus-11_230v.pdf"}]');
INSERT INTO products VALUES (91, 'en', 'm5ztiEX6xMSHCWLRFx3z1', '/rfmb-42', true, '7Nt-KW96OhTCBx-_lWotv', 'RFMB-42', true, '<p>The metall front plate design controller with two output relays.</p><p>The 4 buttons controls on the built-in allow you to directly&nbsp;control the built-in output relays as well as, other iNELS Wireless units.</p><p>The backlight intensity (white LED) of the buttons is automatically&nbsp;adjusted depending on the ambient lighting.</p><p>They can be combined with detectors, controllers, iNELS Wireless or&nbsp;system components.</p><p>Possibility to set the memory of the output state during a power&nbsp;failure and subsequent restoration of the power supply.</p><p>Each of the outputs can be controlled by up to 12/12 channels&nbsp;(1 channel represents one button on the controller).</p><p>Range up to 160 m (in open space).</p><p>Communication frequency with bidirectional protocol RFIO2.</p><p>Power supply AC 230V is galvanically isolated from the output relay&nbsp;contacts</p>', true, NULL, '[]', 'product', 1768906800000, '[]', 'RFMB-42', 'Wireless metal pushbutton controller with switching relays', '[{"image":{"uploadId":483,"alt":""},"alt":""}]', '', '', 21, '[]', 0, 'EUR', '', '', '', '', 1768913690245, 1768913731014, '/rfmb-42                                                                                                                                                         rfmb-42                                                                                                                                                          <p>the metall front plate design controller with two output relays.</p><p>the 4 buttons controls on the built-in allow you to directly&nbsp;control the built-in output relays as well as, other inels wireless units.</p><p>the backlight intensity (white led) of the buttons is automatically&nbsp;adjusted depending on the ambient lighting.</p><p>they can be combined with detectors, controllers, inels wireless or&nbsp;system components.</p><p>possibility to set the memory of the output state during a power&nbsp;failure and subsequent restoration of the power supply.</p><p>each of the outputs can be controlled by up to 12/12 channels&nbsp;(1 channel represents one button on the controller).</p><p>range up to 160 m (in open space).</p><p>communication frequency with bidirectional protocol rfio2.</p><p>power supply ac 230v is galvanically isolated from the output relay&nbsp;contacts</p> public visible', '', '[]');
INSERT INTO products VALUES (135, 'en', 'bxMfpe844MNwsUexCxSFs', '/rfslt-s3', true, 'nw5urgmucAoLDvYDi3REj', 'RFSLT-S3', true, '<p>It measures the level of liquids based on the principle of hydrostatic&nbsp;pressure measurement.</p><p>It consists of a communication unit in a plastic case with IP65 protection&nbsp;placed above the surface and a stainless steel pressure probe connected&nbsp;by a cable lowered to the bottom of the tank.</p><p>The standard length of the probe cable is 3m or 9m.&nbsp;</p><p>The unit communicates wirelessly via the RFIO2 protocol with the devices&nbsp;of the iNELS RF Control system and is powered by a 3V6 lithium&nbsp;battery. The range of the switching actuators from the unit is determined&nbsp;by the building/location, in open space, it is normally 200 meters.</p><p>The unit can also communicate with the eLAN-RF-103 gateway, which&nbsp;conveys level information to the iNELS application.</p><p>In the application, it is possible to manage switching actors, edit notifications, and continuously monitor the level, pressure, temperature and&nbsp;battery discharge status in the unit.</p><p>The unit itself is set up via the iSonda application from an Android/iOS&nbsp;smartphone via the Bluetooth interface (LowEnergy, 4.1 and higher).&nbsp;</p>', true, NULL, '[]', 'product', 1769166000000, '[]', 'RFSLT-S3', 'Wireless hydrostatic level sensor', '[{"image":{"uploadId":793,"alt":""},"alt":""}]', '8595188183994', '8399', 34, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfslt-s3/share_dokumentace/en/manual_rfslt-s3-a4_9q.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFSLT-S3/3D/3d.html', '', 1769172199438, 1769172199438, '/rfslt-s3                                                                                                                                                        rfslt-s3                                                                                                                                                         <p>it measures the level of liquids based on the principle of hydrostatic&nbsp;pressure measurement.</p><p>it consists of a communication unit in a plastic case with ip65 protection&nbsp;placed above the surface and a stainless steel pressure probe connected&nbsp;by a cable lowered to the bottom of the tank.</p><p>the standard length of the probe cable is 3m or 9m.&nbsp;</p><p>the unit communicates wirelessly via the rfio2 protocol with the devices&nbsp;of the inels rf control system and is powered by a 3v6 lithium&nbsp;battery. the range of the switching actuators from the unit is determined&nbsp;by the building/location, in open space, it is normally 200 meters.</p><p>the unit can also communicate with the elan-rf-103 gateway, which&nbsp;conveys level information to the inels application.</p><p>in the application, it is possible to manage switching actors, edit notifications, and continuously monitor the level, pressure, temperature and&nbsp;battery discharge status in the unit.</p><p>the unit itself is set up via the isonda application from an android/ios&nbsp;smartphone via the bluetooth interface (lowenergy, 4.1 and higher).&nbsp;</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfslt-s3/share_dokumentace/en/datasheet_rfslt-s3.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfslt-s3/share_dokumentace/en/ec_declaration_of_conformity_rfslt-s3.pdf"}]');
INSERT INTO products VALUES (120, 'en', 'KeiOC9thnyizTDp0CZihI', '/rftc-6', true, 'dYpHvVH9pLocqKSb7GHyU', 'RFTC-6', true, '<p>Designed to control electric underfl oor heating, direct heating devices&nbsp;or heat sources controlled by potential-free contact&nbsp;</p><p>It allows control of diff erent heating sources in up to 16 independent&nbsp;zones (rooms)</p><p>1xbuilt-in relay 16 A for direct switching</p><p>1x input for external temperature sensor TC</p><p>Built-in digital temperature and humidity sensors</p><p>VA/TN LCD display, 8 touch backlit buttons</p><p>WiFi for thermostat setup (via web browser) and connection to iNELS.&nbsp;Cloud, iNELS APP and MRS via MQTT protocol</p><p>iNELS RFIO2 for wireless communication with iNELS Wireless elements</p><p>Power supply: AC 110 – 230V AC</p><p>Black or white option</p><p>Box for mounting on EU/BS installation boxes</p>', true, NULL, '[]', 'product', 1769166000000, '[]', 'RFTC-6', 'Smart glass multi-zone thermostat with built-in relay', '[{"image":{"uploadId":781,"alt":""},"alt":""}]', '8595188194846', '9484', 29, '[]', 0, 'EUR', 'https://youtu.be/RdTkBiGkr0o', 'https://youtu.be/cndRWlYwvC4', '', '', 1769160636095, 1769160636095, '/rftc-6                                                                                                                                                          rftc-6                                                                                                                                                           <p>designed to control electric underfl oor heating, direct heating devices&nbsp;or heat sources controlled by potential-free contact&nbsp;</p><p>it allows control of diff erent heating sources in up to 16 independent&nbsp;zones (rooms)</p><p>1xbuilt-in relay 16 a for direct switching</p><p>1x input for external temperature sensor tc</p><p>built-in digital temperature and humidity sensors</p><p>va/tn lcd display, 8 touch backlit buttons</p><p>wifi for thermostat setup (via web browser) and connection to inels.&nbsp;cloud, inels app and mrs via mqtt protocol</p><p>inels rfio2 for wireless communication with inels wireless elements</p><p>power supply: ac 110 – 230v ac</p><p>black or white option</p><p>box for mounting on eu/bs installation boxes</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rftc-6/share_dokumentace/en/datasheet_rftc-6.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rftc-6/share_dokumentace/en/ec_declaration_of_conformity_rftc-6.pdf"}]');
INSERT INTO products VALUES (93, 'en', 'FCr9yXOkELCYDs6Lv9k_t', '/rf-touch-2br', true, 'CzueM8vxIrLodkCudOd1c', 'RF Touch-2/BR', true, '<p>RF Touch-2 touch control unit is a system element used for automatic&nbsp;and manual control of switching, dimming, or blind elements and heating&nbsp;control elements within the iNELS Wireless system.</p><p>The control unit is available in two versions:&nbsp;<br>- RF Touch-2/BE – professional version powered via PoE, USB-C, or 10-&nbsp;30V DC screwless terminals and communicating via Wi-Fi and LAN for&nbsp;connection in new home installations, hotels, hospitals, and office buildings&nbsp;<br>- RF Touch-2/BR – simpler version with powered via USB-C or 10-30V&nbsp;screwless terminals and communicating via Wi-Fi for easy connection&nbsp;in renovated rooms without having to connect to the local network</p><p>Both versions communicate wirelessly with iNELS Wireless units using&nbsp;radio frequency and allow up to 40 wireless element addresses and 30&nbsp;detectors to be connected in this way.</p><p>RF Touch-2 touch unit also serves as a communication gateway, so besides&nbsp;direct control via the 4“ capacitive display, it allows communication&nbsp;with the system via the iNELS app and provides connection to the iNELS&nbsp;Cloud.</p><p>RT Touch-2 unit offers a range of automatic functions that can be used&nbsp;even when not connected to a local network, such as controlling heating&nbsp;modes, timers, light scenes, and left buttons.</p><p>RF Touch-2 features integrated temperature and humidity sensors for&nbsp;controlling heating modes.</p><p>Innovative design allows for easy installation in a mounting box</p>', true, NULL, '[]', 'product', 1768906800000, '[]', 'RF Touch-2/BR', 'Wireless touch unit', '[{"image":{"uploadId":752,"alt":""},"alt":""}]', '8595188189743', '8974', 22, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rf_touch-2-br/share_dokumentace/en/manual_rf_touch-2-be_br.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RF_TOUCH-2-BR/3D/3d.html', '', 1768916517982, 1768996576054, '/rf-touch-2br                                                                                                                                                    rf touch-2/br                                                                                                                                                    <p>rf touch-2 touch control unit is a system element used for automatic&nbsp;and manual control of switching, dimming, or blind elements and heating&nbsp;control elements within the inels wireless system.</p><p>the control unit is available in two versions:&nbsp;<br>- rf touch-2/be – professional version powered via poe, usb-c, or 10-&nbsp;30v dc screwless terminals and communicating via wi-fi and lan for&nbsp;connection in new home installations, hotels, hospitals, and office buildings&nbsp;<br>- rf touch-2/br – simpler version with powered via usb-c or 10-30v&nbsp;screwless terminals and communicating via wi-fi for easy connection&nbsp;in renovated rooms without having to connect to the local network</p><p>both versions communicate wirelessly with inels wireless units using&nbsp;radio frequency and allow up to 40 wireless element addresses and 30&nbsp;detectors to be connected in this way.</p><p>rf touch-2 touch unit also serves as a communication gateway, so besides&nbsp;direct control via the 4“ capacitive display, it allows communication&nbsp;with the system via the inels app and provides connection to the inels&nbsp;cloud.</p><p>rt touch-2 unit offers a range of automatic functions that can be used&nbsp;even when not connected to a local network, such as controlling heating&nbsp;modes, timers, light scenes, and left buttons.</p><p>rf touch-2 features integrated temperature and humidity sensors for&nbsp;controlling heating modes.</p><p>innovative design allows for easy installation in a mounting box</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rf_touch-2-br/share_dokumentace/en/datasheet_rf_touch-2_be_br.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rf_touch-2-br/share_dokumentace/en/ec_declaration_of_conformity_rf_touch-2_br.pdf"}]');
INSERT INTO products VALUES (94, 'en', '7B1op_HXkBWNvZGzNKPs-', '/rf-touch-2be', true, 'ExawOX69U1jzpJxMIUj19', 'RF Touch-2/BE', true, '<p>RF Touch-2 touch control unit is a system element used for automatic&nbsp;and manual control of switching, dimming, or blind elements and heating&nbsp;control elements within the iNELS Wireless system.</p><p>The control unit is available in two versions:&nbsp;<br>- RF Touch-2/BE – professional version powered via PoE, USB-C, or 10-&nbsp;30V DC screwless terminals and communicating via Wi-Fi and LAN for&nbsp;connection in new home installations, hotels, hospitals, and office buildings&nbsp;<br>- RF Touch-2/BR – simpler version with powered via USB-C or 10-30V&nbsp;screwless terminals and communicating via Wi-Fi for easy connection&nbsp;in renovated rooms without having to connect to the local network</p><p>Both versions communicate wirelessly with iNELS Wireless units using&nbsp;radio frequency and allow up to 40 wireless element addresses and 30&nbsp;detectors to be connected in this way.</p><p>RF Touch-2 touch unit also serves as a communication gateway, so besides&nbsp;direct control via the 4“ capacitive display, it allows communication&nbsp;with the system via the iNELS app and provides connection to the iNELS&nbsp;Cloud.</p><p>RT Touch-2 unit offers a range of automatic functions that can be used&nbsp;even when not connected to a local network, such as controlling heating&nbsp;modes, timers, light scenes, and left buttons.</p><p>RF Touch-2 features integrated temperature and humidity sensors for&nbsp;controlling heating modes.</p><p>Innovative design allows for easy installation in a mounting box</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RF Touch-2/BE', 'Wireless touch unit', '[{"image":{"uploadId":752,"alt":""},"alt":""}]', '8595188182669', '8266 standard', 22, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rf_touch-2-be/share_dokumentace/en/manual_rf_touch-2-be_br.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RF_TOUCH-2-BE/3D/3d.html', '', 1768996799188, 1768996799188, '/rf-touch-2be                                                                                                                                                    rf touch-2/be                                                                                                                                                    <p>rf touch-2 touch control unit is a system element used for automatic&nbsp;and manual control of switching, dimming, or blind elements and heating&nbsp;control elements within the inels wireless system.</p><p>the control unit is available in two versions:&nbsp;<br>- rf touch-2/be – professional version powered via poe, usb-c, or 10-&nbsp;30v dc screwless terminals and communicating via wi-fi and lan for&nbsp;connection in new home installations, hotels, hospitals, and office buildings&nbsp;<br>- rf touch-2/br – simpler version with powered via usb-c or 10-30v&nbsp;screwless terminals and communicating via wi-fi for easy connection&nbsp;in renovated rooms without having to connect to the local network</p><p>both versions communicate wirelessly with inels wireless units using&nbsp;radio frequency and allow up to 40 wireless element addresses and 30&nbsp;detectors to be connected in this way.</p><p>rf touch-2 touch unit also serves as a communication gateway, so besides&nbsp;direct control via the 4“ capacitive display, it allows communication&nbsp;with the system via the inels app and provides connection to the inels&nbsp;cloud.</p><p>rt touch-2 unit offers a range of automatic functions that can be used&nbsp;even when not connected to a local network, such as controlling heating&nbsp;modes, timers, light scenes, and left buttons.</p><p>rf touch-2 features integrated temperature and humidity sensors for&nbsp;controlling heating modes.</p><p>innovative design allows for easy installation in a mounting box</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rf_touch-2-be/share_dokumentace/en/datasheet_rf_touch-2_be_br.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rf_touch-2-be/share_dokumentace/en/ec_declaration_of_conformity_rf_touch-2_be.pdf"}]');
INSERT INTO products VALUES (136, 'en', 'JUVUBltGfaed_LoC3ioHm', '/rfsou-1', true, '18VLL29BFgP8LoY-cQhVC', 'RFSOU-1', true, '<p>The twilight switch measures the light intensity and based on a set value, it sends the command to switch on the lights or pull the blinds up or down.</p><p>It can be combined with multifunctional switching units and blind switches.</p><p>Integrated sensor for measuring illumination, settable in 3 ranges 1-100,000 lx.</p><p>Selection of function:<br>a) twilight switch – automatically switches on upon a decrease in ambient light intensity, switches off upon an increase (appropriate for garden lights, advertisements, public lighting, etc.).<br>b) light switch – automatically switches on upon an increase in ambient light intensity, switches off upon a decrease (appropriate for offices, restaurants, rooms, etc.).</p><p>Settable delay of up to 2 minutes to eliminate unwanted switching caused by surrounding influences.</p><p>The twilight switch may control up to 32 units in the installation.</p><p>The programming button on the regulator is used for:<br>a) setting a function with a switching or blind unit<br>b) ascertaining battery status<br>c) ascertaining signal quality between the unit and dimmer.</p><p>Battery power (2x 1.5 V AAA batteries - included in supply) with a battery life of around 2 years based on the number of controlled units.</p><p>Range up to 160 m (in open space), if the signal is insufficient between the controller and unit, use the signal repeater RFRP-20N or protocol component RFIO2 that supports this feature.</p><p>Communication frequency with bidirectional protocol RFIO2.</p><p>The increased IP65 protection is suited to mounting on the wall or in the rural environment.</p>', true, NULL, '[]', 'product', 1769166000000, '[]', 'RFSOU-1', 'Twilight switch', '[{"image":{"uploadId":794,"alt":""},"alt":""}]', '8595188147071', '8926', 34, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfsou-1/share_dokumentace/en/manual_rfsou-1.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFSOU-1/3D/3d.html', '', 1769172789347, 1769172789347, '/rfsou-1                                                                                                                                                         rfsou-1                                                                                                                                                          <p>the twilight switch measures the light intensity and based on a set value, it sends the command to switch on the lights or pull the blinds up or down.</p><p>it can be combined with multifunctional switching units and blind switches.</p><p>integrated sensor for measuring illumination, settable in 3 ranges 1-100,000 lx.</p><p>selection of function:<br>a) twilight switch – automatically switches on upon a decrease in ambient light intensity, switches off upon an increase (appropriate for garden lights, advertisements, public lighting, etc.).<br>b) light switch – automatically switches on upon an increase in ambient light intensity, switches off upon a decrease (appropriate for offices, restaurants, rooms, etc.).</p><p>settable delay of up to 2 minutes to eliminate unwanted switching caused by surrounding influences.</p><p>the twilight switch may control up to 32 units in the installation.</p><p>the programming button on the regulator is used for:<br>a) setting a function with a switching or blind unit<br>b) ascertaining battery status<br>c) ascertaining signal quality between the unit and dimmer.</p><p>battery power (2x 1.5 v aaa batteries - included in supply) with a battery life of around 2 years based on the number of controlled units.</p><p>range up to 160 m (in open space), if the signal is insufficient between the controller and unit, use the signal repeater rfrp-20n or protocol component rfio2 that supports this feature.</p><p>communication frequency with bidirectional protocol rfio2.</p><p>the increased ip65 protection is suited to mounting on the wall or in the rural environment.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfsou-1/share_dokumentace/en/datasheet_rfsou-1.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfsou-1/share_dokumentace/en/ec_declaration_of_conformity_rfsou-1_2xaaa.pdf"},{"url":"https://eshop.elkoep.com/documents/rfx/rfsou-1/share_dokumentace/en/ec_declaration_of_conformity_rfsou-1.pdf"}]');
INSERT INTO products VALUES (95, 'en', 'hIC3DiEWeVHvx-_AmQdUB', '/rf-key-40b', true, 'dQpOCwspOyHx9OFgjPCN3', 'RF KEY-40/B', true, '<p>Key fob-sized remote control, available in black and white.</p><p>When pressing the button, it sends a set signal (ON/OFF, dimming,&nbsp;time switching OFF/ON, blinds up/down).</p><p><strong>RF KEY-40</strong>: four buttons enable control of four units independently.</p><p>Battery power supply (3 V CR 2032 battery - included in the supply)&nbsp;with a battery life of around 5 years based on the frequency of use.</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RF KEY-40/B', 'Key fob - 4 buttons - color BLACK', '[{"image":{"uploadId":755,"alt":""},"alt":""}]', '8595188180757', '8075', 23, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rf_key-40/share_dokumentace/aktual/share_dokumentace/en/manual_rf_key-40_60_a4_en-cz.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RF_KEY-40/share_dokumentace/AKTUAL/3D/3d.html', '', 1768997990838, 1768997990838, '/rf-key-40b                                                                                                                                                      rf key-40/b                                                                                                                                                      <p>key fob-sized remote control, available in black and white.</p><p>when pressing the button, it sends a set signal (on/off, dimming,&nbsp;time switching off/on, blinds up/down).</p><p><strong>rf key-40</strong>: four buttons enable control of four units independently.</p><p>battery power supply (3 v cr 2032 battery - included in the supply)&nbsp;with a battery life of around 5 years based on the frequency of use.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rf_key-40/share_dokumentace/aktual/share_dokumentace/en/datasheet_rf_key.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rf_key-40/share_dokumentace/aktual/share_dokumentace/en/ec_declaration_of_conformity_rfkey-40.pdf"}]');
INSERT INTO products VALUES (137, 'en', '_kii8ZUCqfK4cucj-JQJ0', '/rfsf-100', true, '3fYJm8gUQIhfTXvqxK-fQ', 'RFSF-100', true, '<p>The flood detector is used to detect water leakage - the activation occurs the moment the flooding of the contacts located on the underside of the detector occurs.</p><p>Upon detecting water, the flood detector immediately sends a signal to the switched unit, which further switches on a pump, GSM gate or closes a pipe valve.</p><p>Flood detection is signaled by optical and acoustic signaling.&nbsp;</p><p>Range up to 160 m (in open space); if the signal is insufficient between the controller and unit, use the signal repeater RFRP-20 or protocol component RFIO2 that supports this feature.</p>', true, NULL, '[]', 'product', 1769166000000, '[]', 'RFSF-100', 'Flood detector', '[{"image":{"uploadId":797,"alt":""},"alt":""}]', '8595188176828', '7682', 34, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfsf-100/share_dokumentace/en/manual_rfsf-100.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFSF-100/3D/3d.html', '', 1769172807462, 1769172859977, '/rfsf-100                                                                                                                                                        rfsf-100                                                                                                                                                         <p>the flood detector is used to detect water leakage - the activation occurs the moment the flooding of the contacts located on the underside of the detector occurs.</p><p>upon detecting water, the flood detector immediately sends a signal to the switched unit, which further switches on a pump, gsm gate or closes a pipe valve.</p><p>flood detection is signaled by optical and acoustic signaling.&nbsp;</p><p>range up to 160 m (in open space); if the signal is insufficient between the controller and unit, use the signal repeater rfrp-20 or protocol component rfio2 that supports this feature.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfsf-100/share_dokumentace/en/datasheet_rfsf-100.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfsf-100/share_dokumentace/en/ec_declaration_of_conformity_rfsf-100.pdf"}]');
INSERT INTO products VALUES (96, 'en', 'P9FeggJ8u-VXo9OFaCrPU', '/rf-key-40w', true, 'Lc6iYfOBoC9hAuycJm1JK', 'RF KEY-40/W', true, '<p><span>Key fob - sized remote control, available in black and white.</span></p><p><span>When pressing the button, it sends a&nbsp;set signal (ON/OFF, dimming,&nbsp;</span>time switching OFF/ON, blinds up/down).</p><p><strong><span>RF KEY-40</span></strong><span>: four buttons enable control of four units independently.</span></p><p><span>Battery power supply (3 V CR 2032 battery - included in the supply)&nbsp;</span>with a battery life of around 5 years based on the frequency of use.</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RF KEY-40/W', 'Key fob - 4 buttons - color WHITE', '[{"image":{"uploadId":756,"alt":""},"alt":""}]', '8595188180740', '8074', 23, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rf_key-40/share_dokumentace/aktual/share_dokumentace/en/manual_rf_key-40_60_a4_en-cz.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RF_KEY-40/share_dokumentace/AKTUAL/3D/3d.html', '', 1768998073674, 1768998073674, '/rf-key-40w                                                                                                                                                      rf key-40/w                                                                                                                                                      <p><span>key fob - sized remote control, available in black and white.</span></p><p><span>when pressing the button, it sends a&nbsp;set signal (on/off, dimming,&nbsp;</span>time switching off/on, blinds up/down).</p><p><strong><span>rf key-40</span></strong><span>: four buttons enable control of four units independently.</span></p><p><span>battery power supply (3 v cr 2032 battery - included in the supply)&nbsp;</span>with a battery life of around 5 years based on the frequency of use.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rf_key-40/share_dokumentace/aktual/share_dokumentace/en/datasheet_rf_key.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rf_key-40/share_dokumentace/aktual/share_dokumentace/en/ec_declaration_of_conformity_rfkey-40.pdf"}]');
INSERT INTO products VALUES (100, 'en', 'vhdW8SI8_YHXxgiMqKt6G', '/rfsai-61b-sl', true, 'iSiqG_tr3jiGnVvzLSyoR', 'RFSAI-61B-SL', true, '<p>The switching component with one/two output relays is used to control appliances and lights. Switches/buttons connected to the wiring can be used for control.</p><p>They can be combined with Detectors, Controllers, or iNELS RF Control System Components.</p><p>The BOX-SL version offers installation directly in the installation box, ceiling, or cover of the controlled appliance. Easy installation thanks to screwless terminals.</p><p>It allows the connection of switched loads with a total sum of 8 A (2,000 W).</p><p>Functions: for RFSAI 61B-SL and RFSAI 62B-SL - pushbutton, impulse relay, and time functions of a delayed start or return with time setting 2 s-60 min. Any function can be assigned to each output relay. For RFSAI-11B-SL, the button has a fixed function - ON / OFF.</p><p>The external button is assigned in the same way as the wireless one.</p><p>Each of the outputs can be controlled by up to 12/12 channels (1-channel represents one button on the controller). Up to 25 channels for RFSAI-61B-SL and RFSAI-11B-SL.</p><p>The programming button on the component also serves as a manual output control.</p><p>Possibility to set the output status memory in case of failure and subsequent power recovery.</p><p>The elements of the repeater can be set for the components via the RFAF / USB service device, PC, or application.</p><p>Range up to 200 m (outdoors), in case of insufficient signal between the controller and the device, use the RFRP-20 signal repeater or component with the RFIO2 protocol that supports this function.</p><p>Communication with bidirectional RFIO2 protocol.</p><p>The contact material of the AgSnO2 relay enables the switching of light ballasts.</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RFSAI-61B-SL', 'Switch unit with input for external button, 1 channel', '[{"image":{"uploadId":761,"alt":""},"alt":""}]', '8595188182041', '8204', 26, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfsai-61b-sl/share_dokumentace/en/manual_rfsai-xxb-sl.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFSAI-61B-SL/3D/3d.html', '', 1768998729780, 1768998729780, '/rfsai-61b-sl                                                                                                                                                    rfsai-61b-sl                                                                                                                                                     <p>the switching component with one/two output relays is used to control appliances and lights. switches/buttons connected to the wiring can be used for control.</p><p>they can be combined with detectors, controllers, or inels rf control system components.</p><p>the box-sl version offers installation directly in the installation box, ceiling, or cover of the controlled appliance. easy installation thanks to screwless terminals.</p><p>it allows the connection of switched loads with a total sum of 8 a (2,000 w).</p><p>functions: for rfsai 61b-sl and rfsai 62b-sl - pushbutton, impulse relay, and time functions of a delayed start or return with time setting 2 s-60 min. any function can be assigned to each output relay. for rfsai-11b-sl, the button has a fixed function - on / off.</p><p>the external button is assigned in the same way as the wireless one.</p><p>each of the outputs can be controlled by up to 12/12 channels (1-channel represents one button on the controller). up to 25 channels for rfsai-61b-sl and rfsai-11b-sl.</p><p>the programming button on the component also serves as a manual output control.</p><p>possibility to set the output status memory in case of failure and subsequent power recovery.</p><p>the elements of the repeater can be set for the components via the rfaf / usb service device, pc, or application.</p><p>range up to 200 m (outdoors), in case of insufficient signal between the controller and the device, use the rfrp-20 signal repeater or component with the rfio2 protocol that supports this function.</p><p>communication with bidirectional rfio2 protocol.</p><p>the contact material of the agsno2 relay enables the switching of light ballasts.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfsai-61b-sl/share_dokumentace/en/datasheet_rfsai-61b-sl,%20rfsai-62b-sl,%20rfsai-11b-sl,%20rfsai-61bpf-sl.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfsai-61b-sl/share_dokumentace/en/declaration_of_conformity_rfsai-61b-sl_en.pdf"}]');
INSERT INTO products VALUES (101, 'en', 'Fhp4LRPYusQQpH6oG2N8_', '/rfsai-11b-sl', true, 'XEB4HX6qnvOxMK4TbRneE', 'RFSAI-11B-SL', true, '<p>The switching component with one output relay is used to control appliances and lights. Switches/buttons connected to the wiring can be used for control.</p><p>They can be combined with Detectors, Controllers, or iNELS RF Control System Components.</p><p>The BOX-SL version offers installation directly in the installation box, ceiling, or cover of the controlled appliance. Easy installation thanks to screwless terminals.</p><p>It allows the connection of switched loads with a total sum of 8 A (2,000 W).</p><p>Functions: for RFSAI 61B-SL and RFSAI 62B-SL - pushbutton, impulse relay, and time functions of a delayed start or return with time setting 2 s-60 min. Any function can be assigned to each output relay. For RFSAI-11B-SL, the button has a fixed function - ON / OFF.</p><p>The external button is assigned in the same way as the wireless one.</p><p>Each of the outputs can be controlled by up to 12/12 channels (1-channel represents one button on the controller). Up to 25 channels for RFSAI-61B-SL and RFSAI-11B-SL.</p><p>The programming button on the component also serves as a manual output control.</p><p>Possibility to set the output status memory in case of failure and subsequent power recovery.</p><p>The elements of the repeater can be set for the components via the RFAF / USB service device, PC, or application.</p><p>Range up to 200 m (outdoors), in case of insufficient signal between the controller and the device, use the RFRP-20 signal repeater or component with the RFIO2 protocol that supports this function.</p><p>Communication with bidirectional RFIO2 protocol.</p><p>The contact material of the AgSnO2 relay enables the switching of light ballasts.</p>', true, NULL, '[]', 'product', 1768993200000, '[]', 'RFSAI-11B-SL', 'Switch unit with input for external button, 1 channel', '[{"image":{"uploadId":760,"alt":""},"alt":""}]', '8595188183758', '8375', 26, '[]', 0, 'EUR', 'https://eshop.elkoep.com/documents/rfx/rfsai-11b-sl/share_dokumentace/en/manual_rfsai-xxb-sl.pdf', '', 'https://www.elkoep.com/media/import/Elko/RFx/RFSAI-11B-SL/3D/3d.html', '', 1768998800593, 1768998800593, '/rfsai-11b-sl                                                                                                                                                    rfsai-11b-sl                                                                                                                                                     <p>the switching component with one output relay is used to control appliances and lights. switches/buttons connected to the wiring can be used for control.</p><p>they can be combined with detectors, controllers, or inels rf control system components.</p><p>the box-sl version offers installation directly in the installation box, ceiling, or cover of the controlled appliance. easy installation thanks to screwless terminals.</p><p>it allows the connection of switched loads with a total sum of 8 a (2,000 w).</p><p>functions: for rfsai 61b-sl and rfsai 62b-sl - pushbutton, impulse relay, and time functions of a delayed start or return with time setting 2 s-60 min. any function can be assigned to each output relay. for rfsai-11b-sl, the button has a fixed function - on / off.</p><p>the external button is assigned in the same way as the wireless one.</p><p>each of the outputs can be controlled by up to 12/12 channels (1-channel represents one button on the controller). up to 25 channels for rfsai-61b-sl and rfsai-11b-sl.</p><p>the programming button on the component also serves as a manual output control.</p><p>possibility to set the output status memory in case of failure and subsequent power recovery.</p><p>the elements of the repeater can be set for the components via the rfaf / usb service device, pc, or application.</p><p>range up to 200 m (outdoors), in case of insufficient signal between the controller and the device, use the rfrp-20 signal repeater or component with the rfio2 protocol that supports this function.</p><p>communication with bidirectional rfio2 protocol.</p><p>the contact material of the agsno2 relay enables the switching of light ballasts.</p> public visible', 'https://eshop.elkoep.com/documents/rfx/rfsai-11b-sl/share_dokumentace/en/datasheet_rfsai-61b-sl,%20rfsai-62b-sl,%20rfsai-11b-sl,%20rfsai-61bpf-sl.pdf', '[{"url":"https://eshop.elkoep.com/documents/rfx/rfsai-11b-sl/share_dokumentace/en/ec_declaration_of_conformity_rfsai-11b-sl.pdf"}]');
